output-schema.json-structure:
{
  "projections": {
    "month3": {
      "traffic": "string (visitors/month)",
      "value": "string (EUR value)"
    },
    "month6": {
      "traffic": "string",
      "value": "string"
    },
    "month12": {
      "traffic": "string",
      "value": "string"
    }
  },
  "assumptions": [
    "string (assumption 1)",
    "string (assumption 2)"
  ],
  "comparison": {
    "investment": "string (total investment)",
    "potentialReturn": "string (potential annual value)",
    "roi": "string (ROI percentage or range)"
  },
  "summary": "string (1-2 sentence conclusion)"
}

examples.example:
{
  "projections": {
    "month3": {
      "traffic": "+400 lankytoju/men.",
      "value": "€400/men. (2% konversija, €50 AOV)"
    },
    "month6": {
      "traffic": "+1,200 lankytoju/men.",
      "value": "€1,200/men."
    },
    "month12": {
      "traffic": "+2,500 lankytoju/men.",
      "value": "€2,500/men."
    }
  },
  "assumptions": [
    "2% konversijos rodiklis (industrijos vidurkis)",
    "€50 vidutine uzsakymo verte",
    "Konservatyvios prognozs (70% potencialo)"
  ],
  "comparison": {
    "investment": "€5,300 (€500 pradinis + €800/men. x 6 men.)",
    "potentialReturn": "€30,000/metus (12 men. metrikos)",
    "roi": "465% per pirmus metus"
  },
  "summary": "Investicija atsiperka per 4-5 menesius. Organinis srautas lieka ilgalaikis turtas, skirtingai nuo PPC, kuris baigiasi su biudzetu."
}

{
  "projections": {
    "month3": {
      "traffic": "+400 visitors/mo.",
      "value": "€400/mo. (2% conversion, €50 AOV)"
    },
    "month6": {
      "traffic": "+1,200 visitors/mo.",
      "value": "€1,200/mo."
    },
    "month12": {
      "traffic": "+2,500 visitors/mo.",
      "value": "€2,500/mo."
    }
  },
  "assumptions": [
    "2% conversion rate (industry average)",
    "€50 average order value",
    "Conservative projections (70% of potential)"
  ],
  "comparison": {
    "investment": "€5,300 (€500 setup + €800/mo. x 6 mo.)",
    "potentialReturn": "€30,000/year (at 12 mo. metrics)",
    "roi": "465% in first year"
  },
  "summary": "Investment pays for itself within 4-5 months. Unlike PPC, organic traffic remains a long-term asset that continues delivering after the campaign ends."
}
